(() => {
                        const container = {{DOM_CONTEXT}};
                        if(!container) return;
                        const canvas = container.querySelector('.lower-third-canvas');
                        const ctx = canvas ? canvas.getContext('2d') : null;
                        if (canvas) { canvas.width = 1920; canvas.height = 1080; }

                        const BAR_W = 1575; const BAR_H = 170; const MARGIN_L = 20; const MARGIN_R = 40; const OUTER_MARGIN = 30;
                        const x = OUTER_MARGIN; const y = 1080 - BAR_H - 115;
                        let progress = 0, state = 'IN', animationId;
                        const ease = t => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;

                        function animate() {
                            if (!ctx || state === 'HIDDEN') return;
                            ctx.clearRect(0, 0, 1920, 1080);

                            if (state === 'IN') { progress += 0.025; if (progress >= 1) { progress = 1; state = 'STAY'; } }
                            else if (state === 'OUT') { progress -= 0.04; if (progress <= 0) { progress = 0; state = 'HIDDEN'; return; } }

                            const p = ease(progress);
                            const curW = BAR_W * p;

                            ctx.save();
                            const mainGrad = ctx.createLinearGradient(x, y, x + BAR_W, y);
                            mainGrad.addColorStop(0, "#A0A0A0"); mainGrad.addColorStop(0.5, "#E6E6E6"); mainGrad.addColorStop(1, "#FFFFFF");
                            ctx.fillStyle = mainGrad;
                            ctx.fillRect(x, y, curW, BAR_H);
                            ctx.restore();

                            if (p > 0.8) {
                                ctx.save();
                                ctx.globalAlpha = Math.min((progress - 0.8) * 5, 1);
                                ctx.fillStyle = "#000000"; ctx.font = 'bold 80px "Bahnschrift", sans-serif'; ctx.textBaseline = "middle"; ctx.textAlign = "left";
                                const textEl = container.querySelector('#f-tytul-wartosc');
                                const liveText = textEl ? textEl.textContent : '';
                                ctx.fillText(liveText, x + MARGIN_L, y + (BAR_H / 2) + 5, BAR_W - MARGIN_L - MARGIN_R);
                                ctx.restore();
                            }
                            animationId = requestAnimationFrame(animate);
                        }
                        animate();

                        // Wykrywanie zdjęcia z ekranu
                        const observer = new MutationObserver((mutations) => {
                            mutations.forEach((mutation) => {
                                if (mutation.attributeName === 'class' && !container.classList.contains('active')) { state = 'OUT'; }
                            });
                        });
                        observer.observe(container, { attributes: true });
                    })();
